SourceCode.Declaration:
using PwcSLMIntegrationDataProcessor;

class PwcSLMInventTransSync
{
    RecordInsertList    insList = new RecordInsertList(tableNum(PwcInventTransSLM));
}

Method.Source:
public void process(PwcSLMInventTransSyncContract _contract)
{          
    switch(_contract.parmTransType())
    {
        case PwcInventTransSyncType::PurchaseOrder :
            this.processOrder(_contract.parmTransType(), fieldNum(InventTrans, StatusIssue), StatusIssue::None);
            break;

        case PwcInventTransSyncType::PurchaseCreditMemo :
            this.processReturnOrder(_contract.parmTransType(), fieldNum(InventTrans, StatusIssue), StatusIssue::None);
            break;

        case PwcInventTransSyncType::SalesOrder :
            this.processOrder(_contract.parmTransType(), fieldNum(InventTrans, StatusReceipt), StatusReceipt::None);
            break;

        case PwcInventTransSyncType::SalesCreditMemo :
            this.processReturnOrder(_contract.parmTransType(), fieldNum(InventTrans, StatusReceipt), StatusReceipt::None);
            break;

        default :
            this.processOther(_contract.parmTransType());
            break;
    }
}

private void processOrder(PwcInventTransSyncType _type, FieldId _fieldStatusId, int _fieldStatusValue)
{
    InventTrans         invTrans;
    InventTransOrigin   invTransOrigin;
    PwcInventTransSLM   invTransSLM;
    InventDim           invDim;
    InventLocation      invLocation;

    invTrans.clear();
    invTransOrigin.clear();
    invTransSLM.clear();
    invDim.clear();
    invLocation.clear();

    while select invTransOrigin
        where invTransOrigin.ReferenceCategory  ==  this.getTransType(_type)
        join invTrans
        where invTrans.InventTransOrigin    ==  invTransOrigin.RecId
        &&  invTrans.DatePhysical           !=  dateNull()
        &&  invTrans.(_fieldStatusId)       ==  _fieldStatusValue
        && invTrans.PwcCreatedFromSLM       ==  NoYes::No
        join invDim
        where invDim.inventDimId    ==  invTrans.inventDimId
        join invLocation
        where invLocation.InventLocationId  ==  invDim.InventLocationId
        &&  invLocation.PwcSLMSync  ==  NoYes::Yes
        notexists join invTransSLM
        where invTransSLM.RefRecId  ==  invTrans.RecId
        &&  invTransSLM.Success     ==  NoYes::Yes       
    {
        //Prepare request data
        str body = this.getRequsetContract(invTrans, _type);

        //send data to slm
        container conResp = this.sendRequestToSLM(body, _type);

        //handle response
        this.addRecordToList(conResp, invTrans.RecId, body);
    }
    insList.insertDatabase();
}

